exercises.solution:
mvc_to_mtv = {
    'Model': {
        'mtv_equivalent': 'Model',
        'explanation': 'Both handle data structure, database interactions, and business logic. Defined in models.py.',
    },
    'View': {
        'mtv_equivalent': 'Template',
        'explanation': 'MVC View handles presentation. In Django, Templates (HTML files with DTL) handle the visual layer.',
    },
    'Controller': {
        'mtv_equivalent': 'View',
        'explanation': 'MVC Controller handles request logic. In Django, Views (functions/classes in views.py) coordinate data and responses.',
    },
}

for mvc_component, mapping in mvc_to_mtv.items():
    print(f"MVC {mvc_component} -> MTV {mapping['mtv_equivalent']}")
    print(f"  {mapping['explanation']}")
